AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('INV') ) BRK JOIN STOCIVGH IVGH ON (IVGH.GATE_CD = #{ses.gateCd} AND IVGH.BUYER_CD = BRK.BUYER_CD AND IVGH.INV_NUM = BRK.CONT_NUM) JOIN STOCPOHD POHD ON (POHD.GATE_CD = IVGH.GATE_CD AND POHD.BUYER_CD = IVGH.BUYER_CD AND POHD.PO_NUM = IVGH.PO_NUM AND POHD.DEL_FLAG = '0') LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') UNION ALL SELECT BRK.CORP_NO AS CORP_NO , BRK.BRC AS BRC , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , IVAP.AP_NUM AS CONT_NUM , 1 AS CONT_CNT , IVAP.AP_REQ_SUBJECT AS CONT_DESC , IVAP.PY_BUYER_CD AS PY_BUYER_CD , COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM) AS PY_BUYER_CD_CNT , TRUNC((BRK.COST/COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM)), 2) AS PY_COST , TRUNC(((BRK.COST/COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM))/10), 2) AS PY_VAT , BRC.BRNM AS BRNM , BRC.DEPT_NM AS DEPT_NM FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS CONT_NUM , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('AP') ) BRK JOIN STOCIVAP IVAP ON (IVAP.GATE_CD = BRK.GATE_CD AND IVAP.AP_NUM = BRK.CONT_NUM) LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') UNION ALL SELECT BRK.CORP_NO AS CORP_NO , BRK.BRC AS BRC , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , IVAP.AP_NUM AS CONT_NUM , 1 AS CONT_CNT , IVAP.AP_REQ_SUBJECT AS CONT_DESC , IVAP.PY_BUYER_CD AS PY_BUYER_CD , COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM) AS PY_BUYER_CD_CNT , TRUNC((BRK.COST/COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM)), 2) AS PY_COST , TRUNC(((BRK.COST/COUNT(DISTINCT IVAP.BUYER_CD) OVER (PARTITION BY IVAP.AP_NUM))/10), 2) AS PY_VAT , BRC.BRNM AS BRNM , BRC.DEPT_NM AS DEPT_NM FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 4) AS CONT_NUM , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_AP') ) BRK JOIN STOCIVAP IVAP ON (IVAP.GATE_CD = BRK.GATE_CD AND IVAP.AP_NUM = BRK.CONT_NUM) LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') UNION ALL SELECT BRK.CORP_NO AS CORP_NO , BRK.BRC AS BRC , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , IVGH.INV_NUM AS CONT_NUM , 1 AS CONT_CNT , POHD.SUBJECT AS CONT_DESC , IVGH.BUYER_CD AS PY_BUYER_CD , COUNT(DISTINCT IVGH.BUYER_CD) OVER (PARTITION BY IVGH.INV_NUM) AS PY_BUYER_CD_CNT , TRUNC((BRK.COST/COUNT(DISTINCT IVGH.BUYER_CD) OVER (PARTITION BY IVGH.INV_NUM)), 2) AS PY_COST , TRUNC(((BRK.COST/COUNT(DISTINCT IVGH.BUYER_CD) OVER (PARTITION BY IVGH.INV_NUM))/10), 2) AS PY_VAT , BRC.BRNM AS BRNM , BRC.DEPT_NM AS DEPT_NM FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS CONT_NUM , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_AP_BATCH_PRC') ) BRK JOIN STOCIVGH IVGH ON (IVGH.GATE_CD = BRK.GATE_CD AND IVGH.INV_NUM = BRK.CONT_NUM) JOIN STOCPOHD POHD ON (POHD.GATE_CD = IVGH.GATE_CD AND POHD.BUYER_CD = IVGH.BUYER_CD AND POHD.PO_NUM = IVGH.PO_NUM AND POHD.DEL_FLAG = '0') LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') UNION ALL SELECT BRK.CORP_NO AS CORP_NO , BRK.BRC AS BRC , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , VOCM.VC_NO AS CONT_NUM , 1 AS CONT_CNT , VOCM.SUBJECT AS CONT_DESC , (CASE WHEN VOCM.REQ_COM_TYPE = '100' THEN (CASE WHEN VOCM.COMPANY_CD = '1000' THEN VOCM.REQ_COM_CD ELSE VOCM.COMPANY_CD END) ELSE VOCM.COMPANY_CD END ) AS PY_BUYER_CD , COUNT(DISTINCT VOCM.COMPANY_CD) OVER (PARTITION BY VOCM.VC_NO) AS PY_BUYER_CD_CNT , TRUNC((BRK.COST/COUNT(DISTINCT VOCM.COMPANY_CD) OVER (PARTITION BY VOCM.VC_NO)), 2) AS PY_COST , TRUNC(((BRK.COST/COUNT(DISTINCT VOCM.COMPANY_CD) OVER (PARTITION BY VOCM.VC_NO))/10), 2) AS PY_VAT , BRC.BRNM AS BRNM , BRC.DEPT_NM AS DEPT_NM FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS CONT_NUM , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_VOC_CMPL', 'SMS_VOC_REQ') ) BRK JOIN STOCVOCM VOCM ON (VOCM.GATE_CD = BRK.GATE_CD AND VOCM.VC_NO = BRK.CONT_NUM) LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') UNION ALL SELECT BRK.CORP_NO AS CORP_NO , BRK.BRC AS BRC , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , BRK.BUYER_CD AS CONT_NUM , 1 AS CONT_CNT , '고객사 거래요청 및 승인' AS CONT_DESC , BRK.BUYER_CD AS PY_BUYER_CD , 1 AS PY_BUYER_CD_CNT , BRK.COST AS PY_COST , BRK.VAT AS PY_VAT , BRC.BRNM AS BRNM , BRC.DEPT_NM AS DEPT_NM FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_VEND') ) BRK LEFT JOIN TB_CO_BRC BRC ON (BRC.CORP_NO = BRK.CORP_NO AND BRC.BRC = BRK.BRC AND BRC.STSC = '1') ) A WHERE 1=1 ORDER BY A.CONT_TBL_ID, A.ADJ_DT, A.CONT_NUM

SELECT SUM(Z.PY_COST) AS PY_COST_SUM , SUM(Z.PY_VAT) AS PY_VAT_SUM , SUM(Z.PY_COST + Z.PY_VAT) AS PY_AMT FROM ( SELECT (A.COST/COUNT(DISTINCT A.PY_BUYER_CD) OVER (PARTITION BY A.CONT_NUM, CONT_CNT)) AS PY_COST , ((A.COST/COUNT(DISTINCT A.PY_BUYER_CD) OVER (PARTITION BY A.CONT_NUM, CONT_CNT))/10) AS PY_VAT FROM ( SELECT BRK.CORP_NO AS CORP_NO , BRK.ADJ_DT AS ADJ_DT , BRK.COST AS COST , BRK.VAT AS VAT , ECCT.CONT_NUM AS CONT_NUM , ECCT.CONT_CNT AS CONT_CNT , ECPC.PY_BUYER_CD AS PY_BUYER_CD FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 4) AS CONT_NUM , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 5) AS CONT_CNT , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) = 'SMS_CONT_4300' ) BRK JOIN STOCECCT ECCT ON (ECCT.GATE_CD = BRK.GATE_CD AND ECCT.BUYER_CD = BRK.BUYER_CD AND ECCT.CONT_NUM = BRK.CONT_NUM AND ECCT.CONT_CNT = BRK.CONT_CNT) JOIN STOCECCM ECCM ON (ECCM.GATE_CD = ECCT.GATE_CD AND ECCM.BUYER_CD = ECCT.BUYER_CD AND ECCM.CONT_NUM = ECCT.CONT_NUM AND ECCM.CONT_CNT = ECCT.CONT_CNT AND ECCM.DEL_FLAG = '0') JOIN STOCECPC ECPC ON (ECPC.GATE_CD = ECCM.GATE_CD AND ECPC.BUYER_CD = ECCM.BUYER_CD AND ECPC.CONT_NUM = ECCM.CONT_NUM AND ECPC.CONT_CNT = ECCM.CONT_CNT AND ECPC.PR_BUYER_CD = ECCM.PR_BUYER_CD AND ECPC.PR_DEPT_CD = ECCM.PR_DEPT_CD AND ECPC.VENDOR_CD = ECCM.VENDOR_CD AND ECPC.PAY_CNT = '0' AND ECPC.DEL_FLAG = '0') ) A WHERE 1=1 UNION ALL SELECT BRK.COST AS PY_COST , (BRK.COST/10) AS PY_VAT FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
