AND BRK.CORP_NO IN (SELECT CODE_DESC FROM STOCCODD WHERE GATE_CD = #{ses.gateCd} AND CODE_TYPE = 'NH0077' AND LANG_CD = #{ses.langCd} AND USE_FLAG = '1' AND DEL_FLAG = '0')
AND BRK.CORP_NO = #{ses.irsNum}
AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) != 'SMS_CONT_4300' ) Z

SELECT A.CORP_NO , '' AS BRC , A.BRNM , '' AS DEPT_NM , A.ADJ_DT , A.CONT_TBL_ID , GETCOMCODE(#{ses.gateCd}, 'NH0076', A.CONT_TBL_ID, 0, #{ses.langCd}) AS CONT_TBL_NM , A.CONT_CHARGE_CD ,'SMS수수료' AS CONT_CHARGE_NM , A.COST , A.VAT , A.CONT_NUM , A.CONT_CNT , A.CONT_DESC , '' AS PY_BUYER_CD , '' AS PY_BUYER_CD_NM , '' AS PY_BUYER_CD_CNT , '' PY_COST , '' PY_VAT , A.CONT_USER_ID , A.CONT_USER_NM , A.CONT_DEPT_CD , A.CONT_DEPT_NM FROM ( SELECT BRK.CORP_NO AS CORP_NO , CUST.CUST_NM AS BRNM , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , TCCT.CONT_NUM AS CONT_NUM , TCCT.CONT_CNT AS CONT_CNT , TCCT.CONT_DESC AS CONT_DESC , TCCT.CONT_USER_ID AS CONT_USER_ID , GETUSERNAME(#{ses.gateCd}, TCCT.CONT_USER_ID, #{ses.langCd}) AS CONT_USER_NM , TCCT.DEPT_CD AS CONT_DEPT_CD , GETDEPTNAME(#{ses.gateCd}, TCCT.BUYER_CD, TCCT.DEPT_CD, #{ses.langCd}) AS CONT_DEPT_NM , TCCT.BUYER_CD AS BUYER_CD FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 4) AS CONT_NUM , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 5) AS CONT_CNT , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
