AND BRK.CORP_NO = #{ses.irsNum} AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) = 'SMS_TC_REQ' ) BRK JOIN STOCTCCT TCCT ON (TCCT.GATE_CD = BRK.GATE_CD AND TCCT.BUYER_CD = BRK.BUYER_CD AND TCCT.CONT_NUM = BRK.CONT_NUM AND TCCT.CONT_CNT = BRK.CONT_CNT) LEFT JOIN STOCCUST CUST ON (CUST.GATE_CD = TCCT.GATE_CD AND CUST.CUST_CD = TCCT.BUYER_CD) UNION ALL SELECT BRK.CORP_NO AS CORP_NO , CUST.CUST_NM AS BRNM , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , SCTM.APP_DOC_NUM AS CONT_NUM , SCTM.APP_DOC_CNT AS CONT_CNT , SCTM.SUBJECT AS CONT_DESC , SCTM.REG_USER_ID AS CONT_USER_ID , GETUSERNAME(#{ses.gateCd}, SCTM.REG_USER_ID, #{ses.langCd}) AS CONT_USER_NM , TCCT.DEPT_CD AS CONT_DEPT_CD , GETDEPTNAME(#{ses.gateCd}, TCCT.BUYER_CD, TCCT.DEPT_CD, #{ses.langCd}) AS CONT_DEPT_NM , TCCT.BUYER_CD AS BUYER_CD FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 4) AS CONT_NUM , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 5) AS CONT_CNT , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO = #{ses.irsNum} AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_SIGN') ) BRK JOIN STOCSCTM SCTM ON (SCTM.GATE_CD = BRK.GATE_CD AND SCTM.BUYER_CD = BRK.BUYER_CD AND SCTM.APP_DOC_NUM = BRK.CONT_NUM AND SCTM.APP_DOC_CNT = BRK.CONT_CNT) JOIN STOCTCCT TCCT ON (TCCT.GATE_CD = SCTM.GATE_CD AND TCCT.APP_DOC_NUM = SCTM.APP_DOC_NUM AND TCCT.APP_DOC_CNT = SCTM.APP_DOC_CNT) LEFT JOIN STOCCUST CUST ON (CUST.GATE_CD = SCTM.GATE_CD AND CUST.CUST_CD = SCTM.BUYER_CD) UNION ALL SELECT BRK.CORP_NO AS CORP_NO , CUST.CUST_NM AS BRNM , BRK.ADJ_DT AS ADJ_DT , BRK.CONT_TBL_ID , BRK.EPRO_FEE_DSC AS CONT_CHARGE_CD , BRK.COST AS COST , BRK.VAT AS VAT , VOCM.VC_NO AS CONT_NUM , 1 AS CONT_CNT , VOCM.SUBJECT AS CONT_DESC , VOCM.REQ_USER_ID AS CONT_USER_ID , GETUSERNAME(#{ses.gateCd}, VOCM.REQ_USER_ID, #{ses.langCd}) AS CONT_USER_NM , VOCM.REQ_DEPT_CD AS CONT_DEPT_CD , GETDEPTNAME(#{ses.gateCd}, VOCM.REQ_COM_CD, VOCM.REQ_DEPT_CD, #{ses.langCd}) AS CONT_DEPT_NM , VOCM.REQ_COM_CD AS BUYER_CD FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) AS CONT_TBL_ID , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS CONT_NUM , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO = #{ses.irsNum} AND REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 1) IN ('SMS_VOC_CMPL', 'SMS_VOC_REQ') ) BRK JOIN STOCVOCM VOCM ON (VOCM.GATE_CD = BRK.GATE_CD AND VOCM.VC_NO = BRK.CONT_NUM) LEFT JOIN STOCCUST CUST ON (CUST.GATE_CD = VOCM.GATE_CD AND CUST.CUST_CD = VOCM.REQ_COM_CD) ) A WHERE 1=1 ORDER BY A.CONT_TBL_ID, A.ADJ_DT, A.CONT_NUM

SELECT SUM(Z.PY_COST) AS PY_COST_SUM , SUM(Z.PY_VAT) AS PY_VAT_SUM , SUM(Z.PY_COST + Z.PY_VAT) AS PY_AMT FROM ( SELECT A.COST AS PY_COST , A.VAT AS PY_VAT FROM ( SELECT BRK.CORP_NO AS CORP_NO , BRK.ADJ_DT AS ADJ_DT , BRK.COST AS COST , BRK.VAT AS VAT FROM (SELECT BRK.CONT_TBL_PK , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 2) AS GATE_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 3) AS BUYER_CD , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 4) AS CONT_NUM , REGEXP_SUBSTR(BRK.CONT_TBL_PK,'[^@@]+', 1, 5) AS CONT_CNT , BRK.OCC_DT AS ADJ_DT /* 발생일자 */ , BRK.CORP_NO AS CORP_NO /* 사업자번호 */ , BRK.BRC AS BRC /* 사무소코드 */ , BRK.EPRO_FEE_DSC AS EPRO_FEE_DSC/* 수수료구분코드 */ , BRK.COST AS COST /* 단가 */ ,(BRK.COST/10) AS VAT /* 부가세 */ FROM TB_PR_DM_FEE_OCC_BRK BRK WHERE BRK.EPRO_FEE_DSC = '03' /* 수수료구분코드 01 사용료 03 SMS */
AND BRK.OCC_DT BETWEEN #{OCC_FROM_DATE} AND #{OCC_TO_DATE}
AND BRK.CORP_NO = #{ses.irsNum} ) BRK ) A WHERE 1=1 ) Z
